return items.map(item => {
  let raw = String(item.json['website'] ?? '');

  if (!raw || raw === 'undefined' || raw === 'null') {
    return {
      json: {
        row_number: item.json.row_number,
        website_clean: '',
        website_domain: ''
      }
    };
  }
  raw = raw
    .replace(/\u00A0/g, ' ')
    .replace(/\u200B/g, '')
    .replace(/\u200C/g, '')
    .replace(/\u200D/g, '')
    .replace(/\uFEFF/g, '')
    .trim();
  const tokenMatch = raw.match(/https?:\/\/[^\s]+|[a-z0-9.-]+\.[a-z]{2,}(\/[^\s]*)?/i);
  const token = (tokenMatch ? tokenMatch[0] : raw).trim();
  let host = '';
  const m1 = token.match(/^https?:\/\/([^\/?#\s]+)/i);
  if (m1 && m1[1]) {
    host = m1[1];
  } else {
    const m2 = token.match(/^([a-z0-9.-]+\.[a-z]{2,})(?:[\/?#]|$)/i);
    if (m2 && m2[1]) host = m2[1];
  }
  const website_domain = host.replace(/^www\./i, '').toLowerCase();
  const website_clean = website_domain ? `https://${website_domain}/` : '';
  return {
    json: {
      row_number: item.json.row_number,
      website_clean,
      website_domain
    }
  };
});

// n8n Code node

const body = $json.data || '';
const sizeBytes = Buffer.byteLength(body, 'utf8');

// hard size cutoff: 1.5 MB
const MAX_SIZE = 1.5 * 1024 * 1024;

// normalize
const text = body.slice(0, 5000).toLowerCase();

// garbage checks
const looksLikeHtml =
  text.includes('<!doctype html') ||
  text.includes('<html') ||
  text.includes('<head') ||
  text.includes('<body');

if (sizeBytes > MAX_SIZE || looksLikeHtml) {
  return [{ status: 2 }];
}

// sitemap checks
const looksLikeSitemap =
  text.includes('<?xml') &&
  (text.includes('<sitemapindex') ||
   text.includes('<urlset') ||
   text.includes('<url><loc>'));

if (looksLikeSitemap) {
  return [{ status: 1 }];
}

// default: treat as garbage
return [{ status: 2 }];

const xml = $json.data || '';

const locs = [...xml.matchAll(/<loc>(.*?)<\/loc>/gi)].map(m => m[1].trim());

const isSitemapIndex = /<sitemapindex/i.test(xml);
const isUrlSet = /<urlset/i.test(xml);

return [{
  json: {
    sitemap_index: $('Parse json').item.json.sitemap_index ?? null,
    mode: isSitemapIndex ? 1 : isUrlSet ? 2 : null,
    url_1: isUrlSet ? (locs[0] || null) : null,
    url_2: isUrlSet ? (locs[1] || null) : null,
    url_3: isUrlSet ? (locs[2] || null) : null,
  }
}];

// Combine ALL Gemini text chunks into one string, then parse JSON

const items = $input.all();

let text = '';

// Read every item -> every candidate -> every part
for (const it of items) {
  const candidates = it.json?.candidates ?? [];

  for (const candidate of candidates) {
    const parts = candidate?.content?.parts ?? [];

    for (const p of parts) {
      if (typeof p?.text === 'string') {
        text += p.text;
      }
    }
  }
}

text = text.trim();

// Remove code fences if present
text = text.replace(/```json/gi, '').replace(/```/g, '').trim();

// Extract first JSON object
const match = text.match(/\{[\s\S]*\}/);

if (!match) {
  return [{
    json: {
      sitemap_index: null,
      mode: null,
      url_1: null,
      url_2: null,
      url_3: null,
      _raw: text
    }
  }];
}

let jsonStr = match[0].trim();

let obj;
try {
  obj = JSON.parse(jsonStr);
} catch (e) {
  // small repair for trailing commas
  jsonStr = jsonStr.replace(/,\s*([}\]])/g, '$1');
  obj = JSON.parse(jsonStr);
}

return [{
  json: {
    sitemap_index: typeof obj.sitemap_index === 'string' ? obj.sitemap_index : null,
    mode: obj.mode ?? null,
    url_1: typeof obj.url_1 === 'string' ? obj.url_1 : null,
    url_2: typeof obj.url_2 === 'string' ? obj.url_2 : null,
    url_3: typeof obj.url_3 === 'string' ? obj.url_3 : null,
  }
}];

